{ title: "Comprando bilhete de metrô", scene: "Você está em uma estação de metrô em Delhi. Precisa de um cartão de metrô e quer saber qual linha pegar.", lines: [{ who: "them", hi: "नमस्ते, क्या चाहिए?", pt: "Olá, o que precisa?" }, { who: "you", hi: "मुझे मेट्रो कार्ड चाहिए।", pt: "Quero um cartão do metrô." }, { who: "them", hi: "कितने रुपये डालने हैं?", pt: "Quantas rúpias quer colocar?" }, { who: "you", hi: "दो सौ रुपये डालिए।", pt: "Coloque duzentas rúpias." }, { who: "them", hi: "कहाँ जाना है?", pt: "Para onde você quer ir?" }, { who: "you", hi: "मुझे राजीव चौक जाना है।", pt: "Preciso ir para Rajiv Chowk." }, { who: "them", hi: "यह पीली लाइन है।", pt: "Esta é a linha amarela." }, { who: "you", hi: "ट्रेन किस प्लेटफ़ॉर्म से है?", pt: "De qual plataforma sai o trem?" }, { who: "them", hi: "प्लेटफ़ॉर्म दो से।", pt: "Da plataforma dois." }, { who: "you", hi: "अगला स्टॉप कौन सा है?", pt: "Qual é a próxima parada?" }, { who: "them", hi: "अगला स्टॉप कश्मीरी गेट है।", pt: "A próxima parada é Kashmere Gate." }, { who: "you", hi: "धन्यवाद।", pt: "Obrigado/obrigada." }] },
{ title: "Compras em um bazar", scene: "Você está em um bazar de Jaipur olhando uma camisa azul. Quer perguntar preço, negociar e pagar em dinheiro.", lines: [{ who: "them", hi: "आइए, क्या देखना है?", pt: "Venha, o que quer ver?" }, { who: "you", hi: "नीली कमीज़ दिखाइए।", pt: "Mostre uma camisa azul." }, { who: "them", hi: "यह बहुत अच्छी है।", pt: "Esta é muito boa." }, { who: "you", hi: "यह कितने की है?", pt: "Quanto custa esta?" }, { who: "them", hi: "आठ सौ रुपये।", pt: "Oitocentas rúpias." }, { who: "you", hi: "यह बहुत महँगी है।", pt: "Está muito cara." }, { who: "them", hi: "आपके लिए सात सौ।", pt: "Para você, setecentas." }, { who: "you", hi: "छूट मिलेगी?", pt: "Tem desconto?" }, { who: "them", hi: "ठीक है, छह सौ।", pt: "Está bem, seiscentas." }, { who: "you", hi: "अच्छा, मैं नकद दूँगा।", pt: "Certo, vou pagar em dinheiro." }, { who: "them", hi: "धन्यवाद।", pt: "Obrigado/obrigada." }, { who: "you", hi: "धन्यवाद, रंग बहुत सुंदर है।", pt: "Obrigado/obrigada, a cor é muito bonita." }] },
{ title: "Na farmácia", scene: "Você entra em uma farmácia em Goa porque está com dor de cabeça e tosse. Quer remédio e instruções simples.", lines: [{ who: "them", hi: "नमस्ते, क्या समस्या है?", pt: "Olá, qual é o problema?" }, { who: "you", hi: "मुझे सिरदर्द है।", pt: "Estou com dor de cabeça." }, { who: "them", hi: "बुखार है?", pt: "Tem febre?" }, { who: "you", hi: "नहीं, बुखार नहीं है।", pt: "Não, não tenho febre." }, { who: "them", hi: "खाँसी है?", pt: "Tem tosse?" }, { who: "you", hi: "हाँ, थोड़ी खाँसी है।", pt: "Sim, tenho um pouco de tosse." }, { who: "them", hi: "यह दवा लीजिए।", pt: "Tome este remédio." }, { who: "you", hi: "यह दवा कैसे लेनी है?", pt: "Como devo tomar este remédio?" }, { who: "them", hi: "दिन में दो बार पानी के साथ।", pt: "Duas vezes por dia com água." }, { who: "you", hi: "कोई एलर्जी की समस्या है?", pt: "Há problema de alergia?" }, { who: "them", hi: "अगर एलर्जी है, डॉक्टर से मिलिए।", pt: "Se tiver alergia, consulte um médico." }, { who: "you", hi: "ठीक है, धन्यवाद।", pt: "Está bem, obrigado/obrigada." }] },
{ title: "Conversa casual no trem", scene: "Você está em um trem entre Delhi e Jaipur. Uma pessoa local começa uma conversa amigável sobre sua viagem.", lines: [{ who: "you", hi: "नमस्ते, क्या यह सीट खाली है?", pt: "Olá, este assento está livre?" }, { who: "them", hi: "हाँ, बैठिए।", pt: "Sim, sente-se." }, { who: "you", hi: "धन्यवाद।", pt: "Obrigado/obrigada." }, { who: "them", hi: "आप कहाँ से हैं?", pt: "De onde você é?" }, { who: "you", hi: "मैं ब्राज़ील से हूँ।", pt: "Sou do Brasil." }, { who: "them", hi: "भारत में पहली बार?", pt: "Primeira vez na Índia?" }, { who: "you", hi: "हाँ, मेरी पहली बार है।", pt: "Sim, é minha primeira vez." }, { who: "them", hi: "आपको भारत कैसा लगा?", pt: "O que achou da Índia?" }, { who: "you", hi: "भारत बहुत सुंदर और दिलचस्प है।", pt: "A Índia é muito bonita e interessante." }, { who: "them", hi: "हिंदी आती है?", pt: "Você sabe Hindi?" }, { who: "you", hi: "मुझे थोड़ी हिंदी आती है।", pt: "Sei um pouco de Hindi." }, { who: "them", hi: "बहुत अच्छा, आपकी यात्रा शुभ हो।", pt: "Muito bom, que sua viagem seja feliz." }] }
